const today = new Date();
const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
const date = `${yyyy}-${mm}-${dd}`;

return [
  { json: { logtype: 'auth',   url: `http://fileserver:8888/auth-${date}.log` } },
  { json: { logtype: 'nginx',  url: `http://fileserver:8888/nginx_access-${date}.log` } },
  { json: { logtype: 'syslog', url: `http://fileserver:8888/syslog-${date}.log` } }
];

// FIFO queue with a per-run drain cap (prevents runaway / overlap)
const MAX_PER_RUN = 120;   // how many logs to process each trigger

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.queue)) staticData.queue = [];
if (!staticData.pos) staticData.pos = {};

const allItems = $input.all();

// 1) ENQUEUE any new lines to the back of the queue
for (const item of allItems) {
  const raw = item.json.data || item.json.body || item.json.response || '';
  if (!raw || !raw.trim()) continue;

  const url = (item.json.url || '') + '';
  let source = item.json.logtype || 'log';
  if (url.includes('nginx')) source = 'nginx';
  else if (url.includes('syslog')) source = 'syslog';
  else if (url.includes('auth')) source = 'auth';

  const allLines = raw.trim().split('\n').filter(l => l.trim());
  const seen = staticData.pos[source] || 0;
  const startFrom = (seen > allLines.length) ? 0 : seen;   // reset if file rotated
  const newLines = allLines.slice(startFrom);

  for (const line of newLines) {
    let msg = line.trim();
    let tags = [];
    try {
      const obj = JSON.parse(line);
      msg = obj.message || obj.log_message || obj.event?.original || msg;
      if (Array.isArray(obj.tags)) tags = obj.tags.filter(t => t && t !== 'beats_input_codec_plain_applied');
    } catch (e) {}
    staticData.queue.push({ source, event_line: msg, detected_tags: tags });
  }
  staticData.pos[source] = allLines.length;
}

// 2) DRAIN up to MAX_PER_RUN from the FRONT (oldest first)
if (staticData.queue.length === 0) {
  return [{ json: { skip: true, reason: 'Queue empty' } }];
}

const batch = staticData.queue.splice(0, MAX_PER_RUN);   // takes oldest, leaves the rest
const remaining = staticData.queue.length;

return batch.map((e, i) => ({
  json: { ...e, queue_position: i + 1, queue_remaining: remaining }
}));

const input = $input.first().json;
const fullText = (input.output || input.response || input.text || '').trim();

const grab = (l) => { const m = fullText.match(new RegExp(l + ':\\s*([^\\n]+)', 'i')); return m ? m[1].trim() : ''; };

const timestamp = new Date().toISOString();
const filename = `incident-testsys-${timestamp.replace(/[:.]/g,'-')}.txt`;
const model = 'llama3.2:latest';

let type = grab('TYPE') || 'Log Event';
let source = grab('SOURCE') || 'testsys (192.168.253.151) - local system event';
let severity = grab('SEVERITY') || 'Informational';
const summary = grab('SUMMARY') || fullText || 'No analysis returned.';
const actions = [];
for (let n=1;n<=4;n++){ const a=grab('ACTION'+n); if(a) actions.push(a); }

const sevMap = { informational:'Informational', info:'Informational', low:'Low', medium:'Medium', high:'High', critical:'Critical' };
severity = sevMap[(severity||'').toLowerCase()] || 'Informational';

const rank = { Informational:0, Low:1, Medium:2, High:3, Critical:4 };
const shouldAlert = rank[severity] >= 1;

const cp = String.fromCodePoint;
const sevEmoji = { Informational: cp(0x2139), Low: cp(0x1F7E2), Medium: cp(0x1F7E1), High: cp(0x1F7E0), Critical: cp(0x1F534) };
const alarm = cp(0x1F6A8);
const sevColor = { Informational:'#6B7280', Low:'#1E8E3E', Medium:'#C87A00', High:'#E24A3B', Critical:'#7A0010' };
const color = sevColor[severity] || '#6B7280';

function typeEmoji(t){ const s=(t||'').toLowerCase();
  if(s.includes('ssh')||s.includes('brute')||s.includes('auth')||s.includes('login')) return cp(0x1F511);
  if(s.includes('web')||s.includes('sql')||s.includes('xss')) return cp(0x1F489);
  if(s.includes('scan')||s.includes('recon')) return cp(0x1F4E1);
  if(s.includes('priv')||s.includes('sudo')||s.includes('escal')) return cp(0x2B06);
  if(s.includes('malware')||s.includes('ransom')) return cp(0x1F9A0);
  if(s.includes('cron')||s.includes('session')||s.includes('normal')) return cp(0x2705);
  return cp(0x26A0); }

const te = typeEmoji(type);
const se = sevEmoji[severity] || alarm;

const recHtml = actions.map(a=>`<li style="margin:6px 0;color:#2C3E50;line-height:1.5;">${a}</li>`).join('');
const emailHtml = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#F0F4F8;">
  <div style="background:#0D1B2A;padding:22px;border-bottom:4px solid ${color};">
    <h1 style="color:#fff;margin:0;font-size:21px;">${se} ALI ALERT &mdash; <span style="color:${color};">${severity}</span></h1>
    <p style="color:#95A5A6;margin:6px 0 0;font-size:13px;">AI-Powered Autonomous Log Intelligence</p>
  </div>
  <div style="padding:16px 22px;background:#fff;border-bottom:1px solid #e5e7eb;font-size:13px;color:#1A3A5C;">
    <div style="padding:4px 0;"><b>Source Host:</b> testsys (192.168.253.151)</div>
    <div style="padding:4px 0;"><b>Timestamp:</b> ${timestamp}</div>
    <div style="padding:4px 0;"><b>Report File:</b> <span style="font-family:monospace;">${filename}</span></div>
  </div>
  <div style="padding:20px 22px;">
    <div style="background:#fff;border-left:5px solid ${color};border-radius:6px;padding:18px 20px;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
      <div style="font-size:17px;font-weight:bold;color:#1A3A5C;margin-bottom:8px;">${te} ${type}</div>
      <div style="display:inline-block;background:${color};color:#fff;font-size:11px;font-weight:bold;padding:4px 12px;border-radius:12px;margin-bottom:14px;">${severity.toUpperCase()}</div>
      <div style="margin:10px 0;color:#606060;font-size:13px;"><b>Source:</b> ${source}</div>
      <div style="margin:0 0 16px;color:#2C3E50;font-size:14px;line-height:1.6;">${summary}</div>
      <div style="font-size:12px;font-weight:bold;color:${color};margin-bottom:6px;">RECOMMENDED ACTIONS</div>
      <ul style="margin:0;padding-left:22px;">${recHtml}</ul>
    </div>
  </div>
  <div style="background:#0D1B2A;padding:14px;text-align:center;">
    <p style="color:#7F8C8D;font-size:11px;margin:0;">ALI &middot; Autonomous Log Intelligence &middot; aisoc (192.168.253.149) &middot; Ollama ${model}</p>
  </div>
</div>`;

const recText = actions.map((a,i)=>`${i+1}. ${a}`).join('\n');
const slackPayload = {
  text: `${se} ALI ALERT - ${type} (${severity})`,
  blocks: [
    { type:'header', text:{ type:'plain_text', text:`${se} ALI ALERT - ${severity}`, emoji:true } },
    { type:'section', text:{ type:'mrkdwn', text:`${te} *${type}*  \`${severity.toUpperCase()}\`\n*Source:* ${source}\n*Time:* ${timestamp}\n*Report File:* \`${filename}\`` } },
    { type:'section', text:{ type:'mrkdwn', text:`${summary}` } },
    { type:'section', text:{ type:'mrkdwn', text:`*RECOMMENDED ACTIONS*\n${recText}` } },
    { type:'context', elements:[{ type:'mrkdwn', text:`ALI - Autonomous Log Intelligence - Ollama ${model}` }] }
  ]
};

const fileText = `ALI ALERT - ${severity}\nType: ${type}\nSource: ${source}\nTime: ${timestamp}\nReport File: ${filename}\n\nSUMMARY:\n${summary}\n\nRECOMMENDED ACTIONS:\n${recText}\n`;

return [{ json: { analysis: fileText, type, severity, source, summary, timestamp, filename, model, emailHtml, slackPayload, shouldAlert } }];

